mapper.select:
SELECT ID id,PARENT_ID parentId,NAME name,LOGICAL_JUDGMENT logicalJudgment,THRESHOLD_VALUE thresholdValue,TREE_TYPE treeType,IS_ACTIVE isActive
 FROM DGN_COMMON_SETTING where 1=1

    and PARENT_ID = #{parentId}

SELECT ID id,PARENT_ID parentId,NAME name,LOGICAL_JUDGMENT logicalJudgment,THRESHOLD_VALUE thresholdValue,TREE_TYPE treeType,IS_ACTIVE isActive
FROM DGN_COMMON_SETTING where 1=1

    and PARENT_ID = #{parentId}


    and NAME = #{name}


    and IS_ACTIVE = #{isActive}

SELECT ID id,PARENT_ID parentId,NAME name,LOGICAL_JUDGMENT logicalJudgment,THRESHOLD_VALUE thresholdValue,TREE_TYPE treeType,IS_ACTIVE isActive FROM DGN_COMMON_SETTING
#{name}
and parent_id in(select id from DGN_COMMON_SETTING where tree_type='2')

SELECT ID id,PARENT_ID parentId,NAME name,LOGICAL_JUDGMENT logicalJudgment,THRESHOLD_VALUE thresholdValue,TREE_TYPE treeType,IS_ACTIVE isActive FROM DGN_COMMON_SETTING
#{name}
and exists (select t.resource_id from DAC_BILL_ALARM_STATISTICS t where t.resource_id=parent_id)
